import{_ as e,o as i,c as l,a2 as o}from"./chunks/framework.VshInwhI.js";const p=JSON.parse('{"title":"近 30 天 Codex 协作复盘","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/tmp/2026-05-28-codex-history-governance-review.md","filePath":"mango-pmo/tmp/2026-05-28-codex-history-governance-review.md"}'),a={name:"mango-pmo/tmp/2026-05-28-codex-history-governance-review.md"};function d(r,t,n,c,s,h){return i(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="近-30-天-codex-协作复盘" tabindex="-1">近 30 天 Codex 协作复盘 <a class="header-anchor" href="#近-30-天-codex-协作复盘" aria-label="Permalink to &quot;近 30 天 Codex 协作复盘&quot;">​</a></h1><p>日期：2026-05-28</p><h2 id="_1-范围" tabindex="-1">1. 范围 <a class="header-anchor" href="#_1-范围" aria-label="Permalink to &quot;1. 范围&quot;">​</a></h2><ul><li>数据来源：本机 Codex <code>state_5.sqlite</code>、项目相关 rollout JSONL、<code>history.jsonl</code>。</li><li>时间范围：2026-04-28 至 2026-05-28。</li><li>项目范围：<code>/Users/hardy/Work/mango</code> 及其 worktree。</li><li>分析口径：只统计用户发出的消息，不分析 AI 回复内容。</li><li>样本量：48 个项目相关会话，3346 条用户消息。</li></ul><h2 id="_2-高频问题" tabindex="-1">2. 高频问题 <a class="header-anchor" href="#_2-高频问题" aria-label="Permalink to &quot;2. 高频问题&quot;">​</a></h2><p>按用户消息关键词和上下文聚类，近 30 天高频集中在：</p><table tabindex="0"><thead><tr><th>类别</th><th>用户消息数</th><th>暴露的问题</th></tr></thead><tbody><tr><td>后端/API/模块/数据库</td><td>694</td><td>模块边界、API 契约、migration、表字段和版本化规则经常需要返工确认。</td></tr><tr><td>前端/UI/表单/组件</td><td>580</td><td>页面布局、选择组件、状态标签、表单分组和组件独立发布要求需要更硬的规范约束。</td></tr><tr><td>AI 未执行到位</td><td>537</td><td>用户多次追问“为何、依然没有、不是、别忘记”，说明 AI 容易漏需求、误读纠正或验证不足。</td></tr><tr><td>worktree/分支/PR/清理</td><td>427</td><td>AI 容易在分支、PR、worktree、数据库清理上遗漏收尾动作。</td></tr><tr><td>需求澄清/方案规划</td><td>389</td><td>复杂需求需要先拆解对象、枚举、模型、接口、验收项，否则容易直接开干。</td></tr><tr><td>验证/启动/构建</td><td>277</td><td>AI 有过度构建、启动口径不清、验证命令和环境状态说明不足的问题。</td></tr><tr><td>PMO/规范/Agent 遵守</td><td>176</td><td>用户多次要求让 Codex、Claude、Gemini 稳定遵守 PMO，说明入口和规则路由仍需收敛。</td></tr><tr><td>发布/仓库/npm/maven</td><td>120</td><td>Maven、npm、Nexus 账号和发布边界曾出现记忆不稳定，需要硬规则沉淀。</td></tr></tbody></table><h2 id="_3-ai-经常出现的问题" tabindex="-1">3. AI 经常出现的问题 <a class="header-anchor" href="#_3-ai-经常出现的问题" aria-label="Permalink to &quot;3. AI 经常出现的问题&quot;">​</a></h2><ol><li>没有把用户连续补充的约束收敛成硬规则，导致“记录一下，别忘记”类要求反复出现。</li><li>对 PMO 触发范围判断不够精确：简单查看和正式交付容易混淆；正式任务又可能漏读必需规范。</li><li>preflight 规则加载偏粗，一命中前端或后端就加载整套规范，增加执行噪声和上下文负担。</li><li>复杂需求未先拆解业务对象、字典/枚举、数据模型、接口模型、设计模式和验收项，就进入实现。</li><li>前端页面容易按字段顺序或复制页面推进，未稳定遵守搜索区、功能区、列表区、分页区、表单分组和状态标签规则。</li><li>公共组件容易按当前仓库可用实现，未从 npm 独立消费、单体部署、微前端部署和业务复用角度校验。</li><li>后端容易在 API、core、starter、starter-remote、support 边界上摇摆，出现契约污染、远程适配和模块信息职责不清。</li><li>发布任务容易漏账号口径、制品范围、版本验证、仓库检查和发布后回查。</li><li>收尾动作容易漏：PR 合并后 worktree 清理、数据库清理、服务停止、分支状态确认、最终风险说明。</li><li>验证口径容易过重或过轻：前端小改反复 build，或真实接口、数据库、权限链路未接通却表达成完成。</li></ol><h2 id="_4-用户侧协作错误" tabindex="-1">4. 用户侧协作错误 <a class="header-anchor" href="#_4-用户侧协作错误" aria-label="Permalink to &quot;4. 用户侧协作错误&quot;">​</a></h2><ol><li>指令经常分多条追加，关键约束被埋在聊天后半段，容易造成 AI 只执行前半段。</li><li>范围词有时过短，例如“可以”“更新代码”“发布组件”，缺少对象、分支、版本、仓库和验收口径。</li><li>中途会混入无关文本或错别字，增加解析噪声。</li><li>对合并、发布、清理这类高风险操作，有时未一次性说明目标 worktree、数据库、远端分支和是否需要 PR。</li><li>需求会边做边细化，但未及时转成文档或规范，导致后续会话重复解释同一约束。</li><li>UI 需求常以局部问题提出，未先给出字段关系、联动关系、数据来源和状态枚举。</li><li>后端架构判断常以片段问题出现，缺少本次要固化的边界规则和例外条件。</li></ol><h2 id="_5-pmo-优化结论" tabindex="-1">5. PMO 优化结论 <a class="header-anchor" href="#_5-pmo-优化结论" aria-label="Permalink to &quot;5. PMO 优化结论&quot;">​</a></h2><ol><li><code>mango-pmo</code> 继续作为唯一长期规范源；本文件只作为临时复盘，不作为长期规则源。</li><li>preflight 必须从“全局 always + 大包 bundle”改为“最小基线 + 精确专题命中”。</li><li><code>rules/00-dev-flow.md</code> 只保留全局流程、worktree、提交和文档归属，不复制领域规范。</li><li><code>rules/01-delivery-contract.md</code> 只在正式交付、设计驱动、台账驱动或用户明确要求完整交付时加载。</li><li>前端规范按任务精准加载：页面/UI 加载 Element Plus；公共组件加载组件规范和 Monorepo；测试只在测试任务加载。</li><li>后端规范按影响面加载：API、DB、security、persistence、module、test、versioning 分别由路径和关键词触发。</li><li>规则正文保留全部信息，但优先去重、合并重复语义，减少“同一规则多处维护”。</li><li>发布规则必须区分 Maven 后端发布和 npm 前端发布；npm 发布继续复用 Maven/Nexus 账号。</li><li>纯规范、设计文档、复盘文档等不影响服务代码的治理任务，可以在 <code>main</code> 直接修改提交。</li></ol><h2 id="_6-后续检查建议" tabindex="-1">6. 后续检查建议 <a class="header-anchor" href="#_6-后续检查建议" aria-label="Permalink to &quot;6. 后续检查建议&quot;">​</a></h2><ul><li>为 PMO preflight 增加代表性样例验证，覆盖前端页面、前端组件、后端 API、数据库、发布、治理。</li><li>将可自动判断的规则逐步沉淀为 lint、脚本或 review checklist。</li><li>每次用户纠正“不是这个意思”后，若属于长期约束，必须立即归并到 <code>mango-pmo</code> 对应规范。</li></ul>',15)])])}const u=e(a,[["render",d]]);export{p as __pageData,u as default};
